import { axiosInstance } from "@/lib/axios";
import { 
  LoginData, 
  RegisterData, 
  ForgotPasswordData, 
  VerifyCodeData, 
  ResetPasswordData 
} from "@/types/auth";

export const AuthService = {
  login: async (data: LoginData) => {
    const response = await axiosInstance.post("/api/v1/auth/signin", data);
    return response.data;
  },
  
  register: async (data: RegisterData) => {
    const response = await axiosInstance.post("/api/v1/auth/signup", data);
    return response.data;
  },

  forgotPassword: async (data: ForgotPasswordData) => {
    const response = await axiosInstance.post("/api/v1/auth/forgotPasswords", data);
    return response.data;
  },

  verifyResetCode: async (data: VerifyCodeData) => {
    const response = await axiosInstance.post("/api/v1/auth/verifyResetCode", data);
    return response.data;
  },

  resetPassword: async (data: ResetPasswordData) => {
    const response = await axiosInstance.put("/api/v1/auth/resetPassword", data);
    return response.data;
  }
};
