"use client";

import React, { useState } from "react";
import { useForm } from "react-hook-form";
import { yupResolver } from "@hookform/resolvers/yup";
import { loginSchema } from "@/lib/validators";
import { Input } from "@/components/ui/Input";
import { Button } from "@/components/ui/Button";
import { AuthService } from "@/services/auth.service";
import { useAuthStore } from "@/store/auth.store";
import { LoginData } from "@/types/auth";
import toast from "react-hot-toast";
import { useRouter } from "next/navigation";
import Link from "next/link";
import { motion } from "framer-motion";

export default function LoginPage() {
  const router = useRouter();
  const setAuth = useAuthStore((state) => state.setAuth);
  const [isLoading, setIsLoading] = useState(false);

  const {
    register,
    handleSubmit,
    formState: { errors },
  } = useForm<LoginData>({
    resolver: yupResolver(loginSchema),
  });

  const onSubmit = async (data: LoginData) => {
    try {
      setIsLoading(true);
      const res = await AuthService.login(data);
      if (res.message === "success") {
        setAuth(res.token);
        toast.success("Welcome back!");
        router.push("/products"); // Or home page
      }
    } catch (error: unknown) {
      if (error && typeof error === "object" && "response" in error) {
        toast.error((error as { response?: { data?: { message?: string } } }).response?.data?.message || "Invalid credentials");
      } else {
        toast.error("Invalid credentials");
      }
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <motion.div 
      initial={{ opacity: 0, y: 20 }}
      animate={{ opacity: 1, y: 0 }}
      transition={{ duration: 0.5 }}
      className="bg-white dark:bg-slate-900 p-8 rounded-2xl shadow-xl shadow-slate-200/50 dark:shadow-none border border-slate-100 dark:border-slate-800"
    >
      <div className="mb-8 text-center">
        <h1 className="text-3xl font-bold text-slate-900 dark:text-white mb-2">Sign In</h1>
        <p className="text-slate-500 dark:text-slate-400 text-sm">Welcome back to ShopMart</p>
      </div>

      <form onSubmit={handleSubmit(onSubmit)} className="space-y-5">
        <Input
          label="Email Address"
          type="email"
          placeholder="john@example.com"
          {...register("email")}
          error={errors.email?.message}
        />
        
        <div className="space-y-1">
          <Input
            label="Password"
            type="password"
            placeholder="••••••••"
            {...register("password")}
            error={errors.password?.message}
          />
          <div className="flex justify-end">
            <Link 
              href="/forget-password" 
              className="text-xs font-semibold text-orange-600 hover:text-orange-700 dark:text-orange-500 transition-colors"
            >
              Forgot Password?
            </Link>
          </div>
        </div>

        <Button 
          type="submit" 
          className="w-full mt-4" 
          isLoading={isLoading}
        >
          Sign In
        </Button>
      </form>

      <div className="mt-8 text-center text-sm text-slate-600 dark:text-slate-400">
        Don&apos;t have an account?{" "}
        <Link 
          href="/register" 
          className="font-bold text-orange-600 hover:text-orange-700 dark:text-orange-500 transition-colors"
        >
          Create one now
        </Link>
      </div>
    </motion.div>
  );
}
